
'use client';

import { useState } from 'react';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { Bot, Sparkles, Loader2, AlertTriangle, ShieldCheck, UserX } from "lucide-react";
import { analyzeRouteSafety, type AnalyzeRouteSafetyOutput } from '@/ai/flows/analyze-route-safety';

const placeholderReports = `Report 1: Driver on Route R002 was reported for speeding near the old town bridge on April 5th.
Report 2: On Route R004, a parent complained about consistent late arrivals for the past week.
Report 3: Minor accident on R002 at the intersection of Main and 1st street. A car ran a red light. No injuries.
Report 4: Driver on Route R007 seems distracted, often on their phone according to a student's report.`;

export default function SafetyAnalysisPage() {
  const { toast } = useToast();
  const [incidentReports, setIncidentReports] = useState('');
  const [result, setResult] = useState<AnalyzeRouteSafetyOutput | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleAnalysis = async () => {
    if (incidentReports.trim().length < 50) {
      toast({
        variant: 'destructive',
        title: "Insufficient Data",
        description: "Please provide more detailed incident reports for an effective analysis.",
      });
      return;
    }
    
    setIsLoading(true);
    setResult(null);

    try {
      const analysisResult = await analyzeRouteSafety({ incidentReports });
      setResult(analysisResult);
    } catch (error) {
      console.error("Analysis failed:", error);
      toast({
        variant: 'destructive',
        title: "Analysis Failed",
        description: "An error occurred while analyzing the reports. Please try again.",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold font-headline flex items-center gap-2">
          <Bot className="h-8 w-8 text-primary" /> AI Route Safety Analysis
        </h1>
        <p className="text-muted-foreground">
          Analyze incident reports to flag potentially unsafe routes or driver behaviors.
        </p>
      </div>
      
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card>
          <CardHeader>
            <CardTitle>Incident Reports Input</CardTitle>
            <CardDescription>Paste raw incident reports below. One report per line is recommended.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <Textarea
              placeholder={placeholderReports}
              className="min-h-[300px] resize-y"
              value={incidentReports}
              onChange={(e) => setIncidentReports(e.target.value)}
              disabled={isLoading}
            />
            <Button onClick={handleAnalysis} disabled={isLoading} className="w-full">
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Analyzing...
                </>
              ) : (
                <>
                  <Sparkles className="mr-2 h-4 w-4" />
                  Analyze Reports
                </>
              )}
            </Button>
          </CardContent>
        </Card>

        <div className="space-y-8">
          <Card>
            <CardHeader>
              <CardTitle>Analysis Results</CardTitle>
              <CardDescription>AI-generated insights will appear here.</CardDescription>
            </CardHeader>
            <CardContent className="min-h-[300px]">
              {isLoading && (
                <div className="flex flex-col items-center justify-center h-full text-muted-foreground">
                  <Loader2 className="h-12 w-12 animate-spin text-primary" />
                  <p className="mt-4">Processing reports...</p>
                </div>
              )}
              {!isLoading && !result && (
                <div className="flex flex-col items-center justify-center h-full text-muted-foreground">
                  <Bot className="h-12 w-12" />
                  <p className="mt-4 text-center">Results will be displayed here after analysis.</p>
                </div>
              )}
              {result && (
                <div className="space-y-6">
                  <div>
                    <h3 className="font-semibold flex items-center gap-2 mb-2"><ShieldCheck className="text-green-500" /> Summary</h3>
                    <p className="text-sm text-muted-foreground">{result.summary}</p>
                  </div>
                   <div>
                    <h3 className="font-semibold flex items-center gap-2 mb-2"><AlertTriangle className="text-orange-500" /> Potentially Unsafe Routes</h3>
                    <p className="text-sm text-muted-foreground whitespace-pre-line">{result.unsafeRoutes}</p>
                  </div>
                   <div>
                    <h3 className="font-semibold flex items-center gap-2 mb-2"><UserX className="text-red-500" /> Potentially Unsafe Driver Behaviors</h3>
                    <p className="text-sm text-muted-foreground whitespace-pre-line">{result.driverBehaviors}</p>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}
